1	package com.eaglepoint.task136.shared.governance
2	
3	import com.eaglepoint.task136.shared.db.GovernanceDao
4	import kotlinx.coroutines.CoroutineScope
5	import kotlinx.coroutines.Dispatchers
6	import kotlinx.coroutines.Job
7	import kotlinx.coroutines.flow.collectLatest
8	import kotlinx.coroutines.launch
9	
10	interface AnomalyNotifier {
11	    suspend fun notify(ruleName: String, value: Double, detail: String)
12	}
13	
14	class RuleHitObserver(
15	    private val governanceDao: GovernanceDao,
16	    private val anomalyNotifier: AnomalyNotifier,
17	    private val scope: CoroutineScope,
18	) {
19	    fun start(): Job {
20	        return scope.launch(Dispatchers.IO) {
21	            governanceDao.observeOpenRuleHits().collectLatest { hits ->
22	                hits.forEach { hit ->
23	                    if (hit.valueObserved < 0.01 || hit.valueObserved > 9_999.99) {
24	                        anomalyNotifier.notify(
25	                            ruleName = hit.ruleName,
26	                            value = hit.valueObserved,
27	                            detail = "Price outside allowed range $0.01 to $9,999.99",
28	                        )
29	                    }
30	                }
31	            }
32	        }
33	    }
34	}
