1	package com.eaglepoint.task136.shared.viewmodel
2	
3	import com.eaglepoint.task136.shared.db.OrderDao
4	import com.eaglepoint.task136.shared.db.OrderEntity
5	import com.eaglepoint.task136.shared.db.ResourceDao
6	import com.eaglepoint.task136.shared.orders.BookingUseCase
7	import com.eaglepoint.task136.shared.orders.OrderState
8	import com.eaglepoint.task136.shared.orders.OrderStateMachine
9	import com.eaglepoint.task136.shared.orders.PaymentMethod
10	import com.eaglepoint.task136.shared.rbac.Action
11	import com.eaglepoint.task136.shared.rbac.PermissionEvaluator
12	import com.eaglepoint.task136.shared.rbac.ResourceType
13	import com.eaglepoint.task136.shared.rbac.Role
14	import com.eaglepoint.task136.shared.services.ValidationService
15	import kotlinx.coroutines.CoroutineScope
16	import kotlinx.coroutines.Dispatchers
17	import kotlinx.coroutines.SupervisorJob
18	import kotlinx.coroutines.cancel
19	import kotlinx.coroutines.flow.MutableStateFlow
20	import kotlinx.coroutines.flow.StateFlow
21	import kotlinx.coroutines.flow.asStateFlow
22	import kotlinx.coroutines.launch
23	import kotlinx.datetime.Clock
24	import kotlinx.datetime.TimeZone
25	import kotlinx.datetime.toLocalDateTime
26	import kotlin.time.Duration.Companion.minutes
27	
28	data class OrderWorkflowState(
29	    val lastOrderId: String? = null,
30	    val lastOrderState: String? = null,
31	    val suggestedSlots: List<String> = emptyList(),
32	    val error: String? = null,
33	)
34	
35	class OrderWorkflowViewModel(
36	    private val orderDao: OrderDao,
37	    private val resourceDao: ResourceDao,
38	    private val stateMachine: OrderStateMachine,
39	    private val bookingUseCase: BookingUseCase,
40	    private val permissionEvaluator: PermissionEvaluator,
41	    private val validationService: ValidationService,
42	    private val clock: Clock,
43	) {
44	    private var scope = CoroutineScope(SupervisorJob() + Dispatchers.Default)
45	    private val _state = MutableStateFlow(OrderWorkflowState())
46	    val state: StateFlow<OrderWorkflowState> = _state.asStateFlow()
47	
48	    /**
49	     * Resolves the effective user ID for order attribution.
50	     * Companions act on behalf of their delegating user.
51	     */
52	    private fun resolveOrderUserId(actorId: String, delegateForUserId: String?): String {
53	        return delegateForUserId ?: actorId
54	    }
55	
56	    fun createPendingTender(
57	        role: Role,
58	        actorId: String,
59	        resourceId: String,
60	        quantity: Int,
61	        delegateForUserId: String? = null,
62	        paymentMethod: PaymentMethod = PaymentMethod.Cash,
63	    ) {
64	        if (!permissionEvaluator.canAccess(role, ResourceType.Order, "*", Action.Write)) {
65	            _state.value = _state.value.copy(lastOrderState = "Denied")
66	            return
67	        }
68	        scope.launch(Dispatchers.IO) {
69	            val resource = resourceDao.getById(resourceId)
70	            if (resource == null) {
71	                _state.value = _state.value.copy(lastOrderState = "Resource not found")
72	                return@launch
73	            }
74	            if (quantity <= 0) {
75	                _state.value = _state.value.copy(lastOrderState = "Quantity must be at least 1")
76	                return@launch
77	            }
78	            val effectiveUserId = resolveOrderUserId(actorId, delegateForUserId)
79	            val orderId = "ord-${clock.now().toEpochMilliseconds()}"
80	            val now = clock.now().toEpochMilliseconds()
81	            val totalPrice = resource.unitPrice * quantity
82	            val priceError = validationService.validatePrice(totalPrice)
83	            if (priceError != null) {
84	                _state.value = _state.value.copy(lastOrderState = priceError)
85	                return@launch
86	            }
87	            val order = OrderEntity(
88	                id = orderId,
89	                userId = effectiveUserId,
90	                resourceId = resource.id,
91	                state = OrderState.Draft.name,
92	                startTime = now,
93	                endTime = clock.now().plus(30.minutes).toEpochMilliseconds(),
94	                expiresAt = null,
95	                quantity = quantity,
96	                totalPrice = totalPrice,
97	                createdAt = now,
98	                paymentMethod = paymentMethod.name,
99	                notes = if (effectiveUserId != actorId) "createdBy:$actorId" else null,
100	            )
101	            orderDao.upsert(order)
102	            val transitionError = stateMachine.transitionToPendingTender(orderId, role)
103	            if (transitionError != null) {
104	                _state.value = _state.value.copy(lastOrderState = transitionError)
105	                return@launch
106	            }
107	            _state.value = _state.value.copy(lastOrderId = orderId, lastOrderState = OrderState.PendingTender.name)
108	        }
109	    }
110	
111	    internal fun createPendingTenderDemo(
112	        role: Role,
113	        actorId: String,
114	        delegateForUserId: String? = null,
115	        paymentMethod: PaymentMethod = PaymentMethod.Cash,
116	    ) {
117	        scope.launch(Dispatchers.IO) {
118	            val firstResource = resourceDao.page(limit = 1, offset = 0).firstOrNull()
119	            if (firstResource == null) {
120	                _state.value = _state.value.copy(lastOrderState = "No resources available")
121	                return@launch
122	            }
123	            createPendingTender(
124	                role = role,
125	                actorId = actorId,
126	                resourceId = firstResource.id,
127	                quantity = 1,
128	                delegateForUserId = delegateForUserId,
129	                paymentMethod = paymentMethod,
130	            )
131	        }
132	    }
133	
134	    fun confirmLastOrder(role: Role) {
135	        if (!permissionEvaluator.canAccess(role, ResourceType.Order, "*", Action.Write)) {
136	            _state.value = _state.value.copy(lastOrderState = "Denied")
137	            return
138	        }
139	        scope.launch(Dispatchers.IO) {
140	            val orderId = _state.value.lastOrderId ?: return@launch
141	            val success = stateMachine.confirm(orderId, role)
142	            _state.value = _state.value.copy(
143	                lastOrderState = if (success) OrderState.Confirmed.name else "Confirm not allowed",
144	            )
145	        }
146	    }
147	
148	    fun cancelOrder(role: Role) {
149	        if (!permissionEvaluator.canAccess(role, ResourceType.Order, "*", Action.Write)) {
150	            _state.value = _state.value.copy(lastOrderState = "Denied")
151	            return
152	        }
153	        scope.launch(Dispatchers.IO) {
154	            val orderId = _state.value.lastOrderId ?: return@launch
155	            val success = stateMachine.cancel(orderId, role)
156	            _state.value = _state.value.copy(
157	                lastOrderState = if (success) OrderState.Cancelled.name else "Cancel not allowed",
158	            )
159	        }
160	    }
161	
162	    fun requestReturn(role: Role) {
163	        if (!permissionEvaluator.canAccess(role, ResourceType.Order, "*", Action.Write)) {
164	            _state.value = _state.value.copy(lastOrderState = "Denied")
165	            return
166	        }
167	        scope.launch(Dispatchers.IO) {
168	            val orderId = _state.value.lastOrderId ?: return@launch
169	            val success = stateMachine.requestReturn(orderId, role)
170	            _state.value = _state.value.copy(
171	                lastOrderState = if (success) OrderState.ReturnRequested.name else "Return not allowed",
172	            )
173	        }
174	    }
175	
176	    fun completeReturn(role: Role) {
177	        if (!permissionEvaluator.canAccess(role, ResourceType.Order, "*", Action.Approve)) {
178	            _state.value = _state.value.copy(lastOrderState = "Denied")
179	            return
180	        }
181	        scope.launch(Dispatchers.IO) {
182	            val orderId = _state.value.lastOrderId ?: return@launch
183	            val success = stateMachine.completeReturn(orderId, role)
184	            _state.value = _state.value.copy(
185	                lastOrderState = if (success) OrderState.Returned.name else "Complete return not allowed",
186	            )
187	        }
188	    }
189	
190	    fun requestExchange(role: Role) {
191	        if (!permissionEvaluator.canAccess(role, ResourceType.Order, "*", Action.Write)) {
192	            _state.value = _state.value.copy(lastOrderState = "Denied")
193	            return
194	        }
195	        scope.launch(Dispatchers.IO) {
196	            val orderId = _state.value.lastOrderId ?: return@launch
197	            val success = stateMachine.requestExchange(orderId, role)
198	            _state.value = _state.value.copy(
199	                lastOrderState = if (success) OrderState.ExchangeRequested.name else "Exchange not allowed",
200	            )
201	        }
202	    }
203	
204	    fun requestRefund(role: Role) {
205	        if (!permissionEvaluator.canAccess(role, ResourceType.Order, "*", Action.Write) || role == Role.Companion) {
206	            _state.value = _state.value.copy(lastOrderState = "Refund denied for role")
207	            return
208	        }
209	        scope.launch(Dispatchers.IO) {
210	            val orderId = _state.value.lastOrderId ?: return@launch
211	            val success = stateMachine.requestRefund(orderId, role)
212	            _state.value = _state.value.copy(
213	                lastOrderState = if (success) OrderState.RefundRequested.name else "Refund not allowed",
214	            )
215	        }
216	    }
217	
218	    fun completeRefund(role: Role) {
219	        if (!permissionEvaluator.canAccess(role, ResourceType.Order, "*", Action.Approve)) {
220	            _state.value = _state.value.copy(lastOrderState = "Denied")
221	            return
222	        }
223	        scope.launch(Dispatchers.IO) {
224	            val orderId = _state.value.lastOrderId ?: return@launch
225	            val success = stateMachine.completeRefund(orderId, role)
226	            _state.value = _state.value.copy(
227	                lastOrderState = if (success) OrderState.Refunded.name else "Complete refund not allowed",
228	            )
229	        }
230	    }
231	
232	    fun markAwaitingDelivery(role: Role) {
233	        if (!permissionEvaluator.canAccess(role, ResourceType.Order, "*", Action.Write)) {
234	            _state.value = _state.value.copy(lastOrderState = "Denied")
235	            return
236	        }
237	        scope.launch(Dispatchers.IO) {
238	            val orderId = _state.value.lastOrderId ?: return@launch
239	            val success = stateMachine.markAwaitingDelivery(orderId, role)
240	            _state.value = _state.value.copy(
241	                lastOrderState = if (success) OrderState.AwaitingDelivery.name else "Cannot start delivery",
242	            )
243	        }
244	    }
245	
246	    fun confirmDelivery(role: Role, signature: String) {
247	        if (!permissionEvaluator.canAccess(role, ResourceType.Order, "*", Action.Write)) {
248	            _state.value = _state.value.copy(lastOrderState = "Denied")
249	            return
250	        }
251	        scope.launch(Dispatchers.IO) {
252	            val orderId = _state.value.lastOrderId ?: return@launch
253	            val success = stateMachine.confirmDelivery(orderId, signature, role)
254	            _state.value = _state.value.copy(
255	                lastOrderState = if (success) OrderState.Delivered.name else "Cannot confirm delivery",
256	            )
257	        }
258	    }
259	
260	    fun suggestSlots(role: Role, resourceId: String) {
261	        if (!permissionEvaluator.canAccess(role, ResourceType.Order, "*", Action.Read)) {
262	            _state.value = _state.value.copy(suggestedSlots = emptyList())
263	            return
264	        }
265	        scope.launch(Dispatchers.IO) {
266	            val slots = bookingUseCase.findThreeAvailableSlots(
267	                resourceId = resourceId,
268	                duration = 30.minutes,
269	            )
270	            val zone = TimeZone.currentSystemDefault()
271	            _state.value = _state.value.copy(
272	                suggestedSlots = slots.map {
273	                    val start = it.start.toLocalDateTime(zone)
274	                    "${start.date} ${start.time.hour.toString().padStart(2, '0')}:${start.time.minute.toString().padStart(2, '0')}"
275	                },
276	            )
277	        }
278	    }
279	
280	    fun suggestSlots(role: Role) {
281	        scope.launch(Dispatchers.IO) {
282	            val firstResource = resourceDao.page(limit = 1, offset = 0).firstOrNull()
283	            if (firstResource == null) {
284	                _state.value = _state.value.copy(suggestedSlots = emptyList(), error = "No resources available")
285	                return@launch
286	            }
287	            suggestSlots(role, firstResource.id)
288	        }
289	    }
290	
291	    fun loadOrderById(orderId: String) {
292	        scope.launch(Dispatchers.IO) {
293	            val order = orderDao.getById(orderId)
294	            if (order != null) {
295	                _state.value = _state.value.copy(
296	                    lastOrderId = order.id,
297	                    lastOrderState = order.state,
298	                )
299	            }
300	        }
301	    }
302	
303	    fun loadOrderById(orderId: String, actorId: String, delegateForUserId: String? = null) {
304	        scope.launch(Dispatchers.IO) {
305	            val order = if (delegateForUserId.isNullOrBlank()) {
306	                orderDao.getByIdForActor(orderId, actorId)
307	            } else {
308	                orderDao.getByIdForOwnerOrDelegate(orderId, actorId, delegateForUserId)
309	            }
310	            if (order != null) {
311	                _state.value = _state.value.copy(
312	                    lastOrderId = order.id,
313	                    lastOrderState = order.state,
314	                    error = null,
315	                )
316	            } else {
317	                _state.value = _state.value.copy(error = "Order not found or access denied")
318	            }
319	        }
320	    }
321	
322	    fun clearSessionState() {
323	        scope.cancel()
324	        scope = CoroutineScope(SupervisorJob() + Dispatchers.Default)
325	        _state.value = OrderWorkflowState()
326	    }
327	}
