1	package com.eaglepoint.task136.ui
2	
3	import android.os.Bundle
4	import android.view.LayoutInflater
5	import android.view.View
6	import android.view.ViewGroup
7	import android.widget.TextView
8	import androidx.fragment.app.Fragment
9	import androidx.lifecycle.lifecycleScope
10	import com.eaglepoint.task136.R
11	import com.eaglepoint.task136.shared.rbac.Role
12	import com.eaglepoint.task136.shared.viewmodel.AuthViewModel
13	import com.eaglepoint.task136.shared.viewmodel.MeetingWorkflowViewModel
14	import com.eaglepoint.task136.shared.viewmodel.OrderWorkflowViewModel
15	import com.google.android.material.button.MaterialButton
16	import kotlinx.coroutines.flow.collectLatest
17	import kotlinx.coroutines.launch
18	import org.koin.core.context.GlobalContext
19	
20	class CalendarFragment : Fragment() {
21	    private val authVm: AuthViewModel by lazy { GlobalContext.get().get() }
22	    private val orderVm: OrderWorkflowViewModel by lazy { GlobalContext.get().get() }
23	    private val meetingVm: MeetingWorkflowViewModel by lazy { GlobalContext.get().get() }
24	
25	    override fun onCreateView(inflater: LayoutInflater, container: ViewGroup?, savedInstanceState: Bundle?): View {
26	        return inflater.inflate(R.layout.fragment_calendar, container, false)
27	    }
28	
29	    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
30	        super.onViewCreated(view, savedInstanceState)
31	        val role = authVm.state.value.role ?: Role.Viewer
32	        val actorId = authVm.state.value.principal?.userId.orEmpty()
33	        val delegateForUserId = authVm.state.value.principal?.delegateForUserId
34	
35	        val slotText = view.findViewById<TextView>(R.id.slotText)
36	        val meetingStatusText = view.findViewById<TextView>(R.id.meetingStatusText)
37	
38	        view.findViewById<MaterialButton>(R.id.backButton).setOnClickListener {
39	            (activity as? NavigationHost)?.navigateBack()
40	        }
41	        view.findViewById<MaterialButton>(R.id.suggestButton).setOnClickListener {
42	            orderVm.suggestSlots(role)
43	            authVm.touchSession()
44	        }
45	        view.findViewById<MaterialButton>(R.id.submitMeetingButton).setOnClickListener {
46	            meetingVm.submitMeeting(
47	                organizerId = delegateForUserId ?: actorId,
48	                actorId = actorId,
49	                resourceId = "res-1",
50	            )
51	            authVm.touchSession()
52	        }
53	        view.findViewById<MaterialButton>(R.id.openMeetingButton).setOnClickListener {
54	            val meetingId = meetingVm.state.value.meetingId
55	            if (meetingId != null) {
56	                (activity as? NavigationHost)?.navigateToMeetingDetail(meetingId)
57	            }
58	            authVm.touchSession()
59	        }
60	
61	        viewLifecycleOwner.lifecycleScope.launch {
62	            orderVm.state.collectLatest { state ->
63	                slotText.text = if (state.suggestedSlots.isEmpty()) {
64	                    "No suggested slots"
65	                } else {
66	                    state.suggestedSlots.joinToString(separator = "\n")
67	                }
68	            }
69	        }
70	
71	        viewLifecycleOwner.lifecycleScope.launch {
72	            meetingVm.state.collectLatest { state ->
73	                meetingStatusText.text = "${state.status}${state.note?.let { " - $it" } ?: ""}"
74	            }
75	        }
76	    }
77	}
