19	class OrderDetailFragment : Fragment() {
20	    companion object {
21	        fun newInstance(orderId: String) = OrderDetailFragment().apply {
22	            arguments = Bundle().apply { putString("orderId", orderId) }
23	        }
24	    }
25	
26	    private val orderVm: OrderWorkflowViewModel by lazy { GlobalContext.get().get() }
27	    private val authVm: AuthViewModel by lazy { GlobalContext.get().get() }
28	
29	    override fun onCreateView(inflater: LayoutInflater, container: ViewGroup?, savedInstanceState: Bundle?): View {
30	        return inflater.inflate(R.layout.fragment_order_detail, container, false)
31	    }
32	
33	    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
34	        super.onViewCreated(view, savedInstanceState)
35	        val orderId = arguments?.getString("orderId").orEmpty()
36	        val role = authVm.state.value.role ?: Role.Viewer
37	        val actorId = authVm.state.value.principal?.userId.orEmpty()
38	
39	        view.findViewById<TextView>(R.id.orderIdText).text = orderId
40	        view.findViewById<MaterialButton>(R.id.backButton).setOnClickListener {
41	            (activity as? NavigationHost)?.navigateBack()
42	        }
43	
44	        orderVm.loadOrderById(orderId, actorId, authVm.state.value.principal?.delegateForUserId)
45	
46	        view.findViewById<MaterialButton>(R.id.confirmBtn).setOnClickListener { orderVm.confirmLastOrder(role) }
47	        view.findViewById<MaterialButton>(R.id.shipBtn).setOnClickListener { orderVm.markAwaitingDelivery(role) }
48	        view.findViewById<MaterialButton>(R.id.deliverBtn).setOnClickListener { orderVm.confirmDelivery(role, "signed-$actorId") }
49	        view.findViewById<MaterialButton>(R.id.receiptBtn).setOnClickListener { authVm.touchSession() }
50	
51	        viewLifecycleOwner.lifecycleScope.launch {
52	            orderVm.state.collectLatest { state ->
53	                val status = if (state.lastOrderId == orderId) state.lastOrderState ?: "Loading..." else "Loading..."
54	                view.findViewById<TextView>(R.id.statusText).text = status
55	                val errorView = view.findViewById<TextView>(R.id.errorText)
56	                if (state.error != null) {
57	                    errorView.visibility = View.VISIBLE
58	                    errorView.text = state.error
59	                } else {
60	                    errorView.visibility = View.GONE
61	                }
62	            }
63	        }
64	    }
65	}
